8647 // Add the necessary canonical IV and branch recipes required to control the
8648 // loop.
8649 static void addCanonicalIVRecipes(VPlan &Plan, Type *IdxTy, bool HasNUW,
8650                                   DebugLoc DL) {
8651   Value *StartIdx = ConstantInt::get(IdxTy, 0);
8652   auto *StartV = Plan.getOrAddLiveIn(StartIdx);
8653 
8654   // Add a VPCanonicalIVPHIRecipe starting at 0 to the header.
8655   auto *CanonicalIVPHI = new VPCanonicalIVPHIRecipe(StartV, DL);
8656   VPRegionBlock *TopRegion = Plan.getVectorLoopRegion();
8657   VPBasicBlock *Header = TopRegion->getEntryBasicBlock();
8658   Header->insert(CanonicalIVPHI, Header->begin());
8659 
8660   VPBuilder Builder(TopRegion->getExitingBasicBlock());
8661   // Add a VPInstruction to increment the scalar canonical IV by VF * UF.
8662   auto *CanonicalIVIncrement = Builder.createOverflowingOp(
8663       Instruction::Add, {CanonicalIVPHI, &Plan.getVFxUF()}, {HasNUW, false}, DL,
8664       "index.next");
8665   CanonicalIVPHI->addOperand(CanonicalIVIncrement);
8666 
8667   // Add the BranchOnCount VPInstruction to the latch.
8668   Builder.createNaryOp(VPInstruction::BranchOnCount,
8669                        {CanonicalIVIncrement, &Plan.getVectorTripCount()}, DL);
8670 }
