8404   case Instruction::Add:
8405   case Instruction::And:
8406   case Instruction::AShr:
8407   case Instruction::FAdd:
8408   case Instruction::FCmp:
8409   case Instruction::FDiv:
8410   case Instruction::FMul:
8411   case Instruction::FNeg:
8412   case Instruction::FRem:
8413   case Instruction::FSub:
