8425       // The legacy cost model uses SCEV to check if some of the operands are
8426       // constants. To match the legacy cost model's behavior, use SCEV to try
8427       // to replace operands with constants.
8428       ScalarEvolution &SE = *PSE.getSE();
8429       auto GetConstantViaSCEV = [this, &SE](VPValue *Op) {
