8462   // In case of predicated execution (due to tail-folding, or conditional
8463   // execution, or both), pass the relevant mask.
8464   if (Legal->isMaskRequired(HI->Store))
8465     HGramOps.push_back(getBlockInMask(HI->Store->getParent()));
